   466Рєњ// ТИЁжЎцуј░ТюЅуџёWebIDEжЁЇуй«
   467Рєњfunc (c *Controller) clearWebIDEConfig(deployment *appsv1.Deployment) {
   468Рєњ	container := &deployment.Spec.Template.Spec.Containers[0]
   469Рєњ
   470Рєњ	// ТИЁжЎцтЉйС╗ц№╝ѕтЈфТюЅтйЊтЉйС╗цтїЁтљФWebIDEуЏИтЁ│тЉйС╗цТЌХТЅЇТИЁжЎц№╝Ѕ
   471Рєњ	if len(container.Command) > 0 {
   472Рєњ		commandStr := strings.Join(container.Command, " ")
   473Рєњ		if strings.Contains(commandStr, "code-server") || strings.Contains(commandStr, "jupyter lab") {
   474Рєњ			container.Command = nil
   475Рєњ		}
   476Рєњ	}
   477Рєњ
   478Рєњ	// ТИЁжЎцуЏИтЁ│уФ»тЈБ
   479Рєњ	newPorts := make([]corev1.ContainerPort, 0, len(container.Ports))
   480Рєњ	for _, port := range container.Ports {
   481Рєњ		if port.Name != "vscode" && port.Name != "jupyter" {
   482Рєњ			newPorts = append(newPorts, port)
   483Рєњ		}
   484Рєњ	}
   485Рєњ	container.Ports = newPorts
   486Рєњ}
