   763Рєњfunc podStatus(targetPod *corev1.Pod) string {
   764Рєњ	var status string
   765Рєњ	// ТБђТЪЦ Pod Тў»тљдТГБтюетѕажЎцСИГ№╝ѕTerminating№╝Ѕ
   766Рєњ	if targetPod.DeletionTimestamp != nil {
   767Рєњ		status = devmachines.StatusTerminating
   768Рєњ	} else {
   769Рєњ		// Set machine status based on pod status
   770Рєњ		switch targetPod.Status.Phase {
   771Рєњ		case corev1.PodPending:
   772Рєњ			// ТБђТЪЦТў»тљдТюЅт«╣тЎетљ»тіетц▒У┤Ц
   773Рєњ			if hasCrashLoopBackOff(targetPod) {
   774Рєњ				status = devmachines.StatusCrashLoopBackOff
   775Рєњ			} else {
   776Рєњ				status = devmachines.StatusPending
   777Рєњ			}
   778Рєњ		case corev1.PodRunning:
   779Рєњ			// Check if all containers are ready
   780Рєњ			allContainersReady := true
   781Рєњ			for _, containerStatus := range targetPod.Status.ContainerStatuses {
   782Рєњ				if !containerStatus.Ready {
   783Рєњ					allContainersReady = false
   784Рєњ					// ТБђТЪЦТў»тљдТюЅт«╣тЎетцёС║ј Crash уіХТђЂ
   785Рєњ					if isContainerCrashing(containerStatus) {
   786Рєњ						status = devmachines.StatusCrashLoopBackOff
   787Рєњ						break
   788Рєњ					}
   789Рєњ				}
   790Рєњ			}
   791Рєњ			if allContainersReady {
   792Рєњ				status = devmachines.StatusRunning
   793Рєњ			}
   794Рєњ		case corev1.PodSucceeded:
   795Рєњ			status = devmachines.StatusStopped
   796Рєњ		case corev1.PodFailed:
   797Рєњ			// тї║тѕєТЎ«жђџтц▒У┤Цтњї CrashLoopBackOff
   798Рєњ			if hasCrashLoopBackOff(targetPod) {
   799Рєњ				status = devmachines.StatusCrashLoopBackOff
   800Рєњ			} else {
   801Рєњ				status = devmachines.StatusError
   802Рєњ			}
   803Рєњ		case corev1.PodUnknown:
   804Рєњ			status = devmachines.StatusUnknown
   805Рєњ		default:
   806Рєњ			status = devmachines.StatusUnknown
   807Рєњ		}
   808Рєњ	}
   809Рєњ	return status
   810Рєњ}
