   690Рєњfunc (c *Controller) convertDeploymentToDevMachine(deployment *appsv1.Deployment) (*devmachines.DevMachine, error) {
   691Рєњ	if len(deployment.Spec.Template.Spec.Containers) == 0 {
   692Рєњ		return nil, fmt.Errorf("deployment %s/%s has no containers", deployment.Namespace, deployment.Name)
   693Рєњ	}
   694Рєњ	container := deployment.Spec.Template.Spec.Containers[0]
   695Рєњ	envMap := make(map[string]string)
   696Рєњ	for _, env := range container.Env {
   697Рєњ		envMap[env.Name] = env.Value
   698Рєњ	}
   699Рєњ	machine := &devmachines.DevMachine{
   700Рєњ		CreateDevMachineRequest: devmachines.CreateDevMachineRequest{
   701Рєњ			Namespace:       deployment.Namespace,
   702Рєњ			Name:            deployment.Name,
   703Рєњ			Image:           container.Image,
   704Рєњ			CPU:             container.Resources.Limits.Cpu().String(),
   705Рєњ			Memory:          container.Resources.Limits.Memory().String(),
   706Рєњ			Labels:          deployment.Labels,
   707Рєњ			Annotations:     deployment.Annotations,
   708Рєњ			EnvironmentVars: envMap,
   709Рєњ		},
   710Рєњ	}
   711Рєњ	// Get creation time
   712Рєњ	machine.CreatedAt = deployment.CreationTimestamp.Time.Format(time.DateTime)
   713Рєњ	// Get last updated time from deployment status
   714Рєњ	if len(deployment.Status.Conditions) > 0 {
   715Рєњ		machine.LastUpdated = deployment.Status.Conditions[0].LastUpdateTime.Time.Format(time.DateTime)
   716Рєњ	}
   717Рєњ	// Get pod status
   718Рєњ	pods, err := c.client.CoreV1().Pods(deployment.Namespace).List(context.Background(), metav1.ListOptions{
   719Рєњ		LabelSelector: fmt.Sprintf("devmachine.tap.ai.com/name=%s", deployment.Name),
   720Рєњ	})
   721Рєњ	if err != nil && !errors.IsNotFound(err) {
   722Рєњ		machine.Status = devmachines.StatusError
   723Рєњ		return machine, fmt.Errorf("failed to get pods for deployment %s/%s: %w", deployment.Namespace, deployment.Name, err)
   724Рєњ	}
   725Рєњ
   726Рєњ	if pods == nil {
   727Рєњ		pods = &corev1.PodList{Items: []corev1.Pod{}}
   728Рєњ	}
   729Рєњ
   730Рєњ	if deployment.Spec.Replicas != nil && *deployment.Spec.Replicas == 0 {
   731Рєњ		if len(pods.Items) == 0 {
   732Рєњ			machine.Status = devmachines.StatusStopped
   733Рєњ		} else {
   734Рєњ			machine.Status = devmachines.StatusTerminating
   735Рєњ		}
   736Рєњ		return machine, nil
   737Рєњ	}
   738Рєњ
   739Рєњ	// Handle case when no pods exist but replicas > 0
   740Рєњ	if len(pods.Items) == 0 {
   741Рєњ		machine.Status = devmachines.StatusUnknown
   742Рєњ		return machine, nil
   743Рєњ	}
   744Рєњ
   745Рєњ	// Find the most recent pod for status details
   746Рєњ	var targetPod *corev1.Pod
   747Рєњ	for i := range pods.Items {
   748Рєњ		pod := &pods.Items[i]
   749Рєњ		if targetPod == nil || pod.CreationTimestamp.After(targetPod.CreationTimestamp.Time) {
   750Рєњ			targetPod = pod
   751Рєњ		}
   752Рєњ	}
   753Рєњ
   754Рєњ	if targetPod != nil {
   755Рєњ		machine.PodName = targetPod.Name
   756Рєњ		machine.NodeName = targetPod.Spec.NodeName
   757Рєњ		machine.PodStatus = string(targetPod.Status.Phase)
   758Рєњ		machine.Status = podStatus(targetPod)
   759Рєњ	}
   760Рєњ	return machine, nil
   761Рєњ}
   762Рєњ
   763Рєњfunc podStatus(targetPod *corev1.Pod) string {
   764Рєњ	var status string
   765Рєњ	// ТБђТЪЦ Pod Тў»тљдТГБтюетѕажЎцСИГ№╝ѕTerminating№╝Ѕ
   766Рєњ	if targetPod.DeletionTimestamp != nil {
   767Рєњ		status = devmachines.StatusTerminating
   768Рєњ	} else {
   769Рєњ		// Set machine status based on pod status
   770Рєњ		switch targetPod.Status.Phase {
   771Рєњ		case corev1.PodPending:
   772Рєњ			// ТБђТЪЦТў»тљдТюЅт«╣тЎетљ»тіетц▒У┤Ц
   773Рєњ			if hasCrashLoopBackOff(targetPod) {
   774Рєњ				status = devmachines.StatusCrashLoopBackOff
   775Рєњ			} else {
